from microcoapy import CoAP, Resource

class TemperatureSensor(Resource):
    def __init__(self):
        super().__init__()
        self.temperature = 25.0  # Default temperature

    def get(self):
        return str(self.temperature)

    def put(self, payload):
        try:
            self.temperature = float(payload)
            return "Temperature updated"
        except ValueError:
            return "Invalid temperature value", 400

class LightActuator(Resource):
    def __init__(self):
        super().__init__()
        self.state = "off"  # Default state

    def get(self):
        return self.state

    def put(self, payload):
        if payload in ["on", "off"]:
            self.state = payload
            return "Light state updated"
        return "Invalid state value", 400

coap_server = CoAP()
coap_server.add_resource('/sensors/temp', TemperatureSensor())
coap_server.add_resource('/actuators/light', LightActuator())

if __name__ == "__main__":
    coap_server.start()